// Forward WebView console errors/warnings to the host stderr (the WebView's
// own console is invisible from a terminal launch). Install once at module
// load so renderer crashes during early mount are still captured.
(() => {
  const fwd = (level: string, args: unknown[]) => {
    try {
      const msg = args
        .map((a) => {
          if (a instanceof Error) return `${a.message}\n${a.stack ?? ''}`;
          if (typeof a === 'string') return a;
          try {
            return JSON.stringify(a);
          } catch {
            return String(a);
          }
        })
        .join(' ');
      invoke('js_log', { level, msg }).catch(() => {});
    } catch {
      /* never let logging break the app */
    }
  };
  const origErr = console.error.bind(console);
  const origWarn = console.warn.bind(console);
  console.error = (...args: unknown[]) => {
    fwd('error', args);
    origErr(...args);
  };
  console.warn = (...args: unknown[]) => {
    fwd('warn', args);
    origWarn(...args);
  };
  window.addEventListener('error', (e) => {
    fwd('uncaught', [e.message, `${e.filename}:${e.lineno}:${e.colno}`, e.error]);
  });
  window.addEventListener('unhandledrejection', (e) => {
    fwd('rejection', [e.reason]);
  });
})();

