/// Read-only settings + ~/.moonshine status panel. Surfaces the resolved
/// binaries, guard home, identity markers, and live REPL state so the operator
/// can confirm the sovereign toolchain is wired correctly.
function SettingsPanel({
  onClose,
  session,
  onSession,
  vimEnabled,
  onVim,
  agentGenTokens,
  onAgentGenTokens,
  accentColor,
  onAccentColor,
}: {
  onClose: () => void;
  session: AuthSession | null;
  onSession: (s: AuthSession | null) => void;
  vimEnabled: boolean;
  onVim: (on: boolean) => void;
  agentGenTokens: number;
  onAgentGenTokens: (tokens: number) => void;
  accentColor: string;
  onAccentColor: (color: string) => void;
}) {
  const [info, setInfo] = useState<SystemInfo | null>(null);
  const [err, setErr] = useState('');
  const [signinErr, setSigninErr] = useState('');
  const [signingIn, setSigningIn] = useState(false);
  const [accentDraft, setAccentDraft] = useState(accentColor);

  useEffect(() => {
    setAccentDraft(accentColor);
  }, [accentColor]);

  const commitAccentDraft = () => {
    const normalized = normalizeAccentColor(accentDraft);
    onAccentColor(normalized);
    setAccentDraft(normalized);
  };

  const signIn = async (provider: string) => {
    setSigningIn(true);
    setSigninErr('');
    try {
      onSession(await runCardYogaSignin(provider));
    } catch (e) {
      setSigninErr(String(e));
    } finally {
      setSigningIn(false);
    }
  };
  const signOut = () => {
    localStorage.removeItem(AUTH_STORAGE_KEY);
    onSession(null);
  };

  useEffect(() => {
    invoke<SystemInfo>('system_info')
      .then(setInfo)
      .catch((e) => setErr(String(e)));
  }, []);

  const row = (label: string, value: React.ReactNode) => (
    <div className="settings-row">
      <span className="settings-label">{label}</span>
      <span className="settings-value">{value}</span>
    </div>
  );

  return (
    <div className="settings-panel">
      <div className="settings-head">
        <span className="settings-title">settings · ~/.moonshine</span>
        <button className="btn btn-toggle" onClick={onClose} title="close">
          ✕
        </button>
      </div>
      {err && <div className="error-msg">{err}</div>}
      {!info && !err && <div className="empty-pane">loading…</div>}
      {info && (
        <div className="settings-body">
          <div className="settings-section">runtime</div>
          <div className={`doctor-card ${info.ready ? 'ready' : 'blocked'}`}>
            <div className="doctor-head">
              <span className={`status-dot ${info.ready ? 'ok' : 'bad'}`} />
              <strong>{info.ready ? 'ready' : 'needs attention'}</strong>
            </div>
            {info.problems.length > 0 ? (
              <ul className="doctor-list">
                {info.problems.map((problem) => (
                  <li key={problem}>{problem}</li>
                ))}
              </ul>
            ) : (
              <span className="dim sm">runtime binaries, identity, and guard home are available</span>
            )}
          </div>

          <ModelManager />
          <SkymeshManager />
          <MobileBridgeManager />

          <div className="settings-section">appearance</div>
          <div className="settings-row">
            <span className="settings-label">accent</span>
            <span className="settings-value accent-color-control">
              <input
                className="accent-color-picker"
                type="color"
                value={accentColor}
                onChange={(e) => onAccentColor(e.currentTarget.value)}
                title="pick accent color"
              />
              <input
                className="input-sm accent-color-input"
                value={accentDraft}
                onChange={(e) => setAccentDraft(e.currentTarget.value)}
                onBlur={commitAccentDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    commitAccentDraft();
                  }
                }}
                aria-label="accent hex color"
              />
              {ACCENT_SWATCHES.map((color) => (
                <button
                  key={color}
                  className={`accent-swatch ${accentColor === color ? 'active' : ''}`}
                  style={{ backgroundColor: color }}
                  onClick={() => onAccentColor(color)}
                  title={color}
                />
              ))}
              <button
                className="btn btn-mini"
                onClick={() => onAccentColor(DEFAULT_ACCENT_COLOR)}
                title="reset accent color"
              >
                reset
              </button>
            </span>
          </div>

          <div className="settings-section">agent responses</div>
          <div className="settings-row">
            <span className="settings-label">token cap</span>
            <span className="settings-value token-cap-control">
              <input
                className="input-sm token-cap-input"
                type="number"
                min={MIN_AGENT_GEN_TOKENS}
                max={MAX_AGENT_GEN_TOKENS}
                step={1}
                value={agentGenTokens}
                onChange={(e) => onAgentGenTokens(Number(e.currentTarget.value))}
                title="MOONSHINE_AGENT_GEN_TOKENS"
              />
              {[128, 256, 512].map((tokens) => (
                <button
                  key={tokens}
                  className={`cap-chip ${agentGenTokens === tokens ? 'active' : ''}`}
                  onClick={() => onAgentGenTokens(tokens)}
                  title={`set response cap to ${tokens} generated tokens`}
                >
                  {tokens}
                </button>
              ))}
            </span>
          </div>
          <div className="settings-hint compact">
            Applies to shell fallback and <code>agent chat</code> turns through{' '}
            <code>MOONSHINE_AGENT_GEN_TOKENS</code>. A changed cap restarts the
            warm REPL before the next command.
          </div>

          <div className="settings-section">account · card.yoga</div>
          {session ? (
            <div className="account-card">
              {session.identity.picture ? (
                <img className="account-avatar" src={session.identity.picture} alt="" />
              ) : (
                <span className="account-avatar avatar-initial">
                  {(session.identity.name || session.identity.email || '?')
                    .charAt(0)
                    .toUpperCase()}
                </span>
              )}
              <div className="account-meta">
                <div className="account-name">
                  {session.identity.name || session.identity.email || 'signed in'}
                </div>
                <code className="account-did">{session.rootDid}</code>
              </div>
              <button className="btn btn-mini" onClick={signOut}>
                sign out
              </button>
            </div>
          ) : (
            <div className="signin-row">
              <span className="dim">sign in for a DID-token session</span>
              <div className="signin-buttons">
                {['google', 'github', 'apple'].map((p) => (
                  <button
                    key={p}
                    className="btn btn-mini"
                    onClick={() => signIn(p)}
                    disabled={signingIn}
                  >
                    {p}
                  </button>
                ))}
              </div>
              {signingIn && <span className="dim sm">opening browser… complete sign-in there</span>}
              {signinErr && <div className="error-msg">{signinErr}</div>}
            </div>
          )}

          <div className="settings-section">identity</div>
          {row(
            'status',
            info.identity_present ? (
              <span className="ok">admitted</span>
            ) : (
              <span className="bad">no identity — run `moonshine init`</span>
            )
          )}
          {info.identity_path && row('path', <code>{info.identity_path}</code>)}
          {row('REPL', info.repl_active ? (
            <span className="ok">live (sub-1ms)</span>
          ) : (
            <span className="dim">idle — starts on first command</span>
          ))}

          <div className="settings-section">sovereign toolchain</div>
          {row('moonshine', <code>{info.moonshine_bin}</code>)}
          {row('monster-guard', <code>{info.guard_bin}</code>)}
          {row('guard home', <code>{info.guard_home}</code>)}

          <AdmissionsManager />

          <div className="settings-section">editing</div>
          <div className="settings-toggle">
            <span>
              vim keybindings
              <div className="dim sm">
                normal/insert modes on the prompt — i/a, h/l, w/b, 0/$, x, D, dd,
                j/k history, Esc to normal
              </div>
            </span>
            <button
              className={`toggle-switch ${vimEnabled ? 'on' : ''}`}
              onClick={() => onVim(!vimEnabled)}
            >
              {vimEnabled ? 'on' : 'off'}
            </button>
          </div>

          <div className="settings-hint">
            Binary paths come from <code>MOONSHINE_BIN</code> /{' '}
            <code>MONSTER_GUARD_BIN</code> (env) then <code>PATH</code>. The guard
            home holds UCAN grants + revocations.
          </div>
        </div>
      )}
    </div>
  );
}

/// Manage admitted binaries and their UCAN capability delegations: list each
/// grant (name, caps, expiry), add a new admission, lock one down (revoke), or
/// remove it entirely. All mutations shell out to monster-guard via the backend.
function AdmissionsManager() {
  const [items, setItems] = useState<Admission[] | null>(null);
  const [err, setErr] = useState('');
  const [busy, setBusy] = useState('');
  const [adding, setAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newCaps, setNewCaps] = useState<string[]>(['exec']);
  const [newTtlDays, setNewTtlDays] = useState(30);

  const reload = async () => {
    try {
      setItems(await invoke<Admission[]>('list_admissions'));
      setErr('');
    } catch (e) {
      setErr(String(e));
    }
  };
  useEffect(() => {
    reload();
  }, []);

  const toggleCap = (cap: string) =>
    setNewCaps((cs) => (cs.includes(cap) ? cs.filter((c) => c !== cap) : [...cs, cap]));

  const submitNew = async () => {
    const name = newName.trim();
    if (!name) return;
    setBusy(name);
    try {
      await invoke('delegate_admission', {
        name,
        caps: newCaps,
        ttlSecs: Math.max(1, Math.round(newTtlDays * 86400)),
      });
      setNewName('');
      setNewCaps(['exec']);
      setAdding(false);
      await reload();
    } catch (e) {
      setErr(String(e));
    } finally {
      setBusy('');
    }
  };

  const revoke = async (name: string) => {
    setBusy(name);
    try {
      await invoke('revoke_admission', { name });
      await reload();
    } catch (e) {
      setErr(String(e));
    } finally {
      setBusy('');
    }
  };

  const remove = async (name: string) => {
    setBusy(name);
    try {
      await invoke('remove_admission', { name });
      await reload();
    } catch (e) {
      setErr(String(e));
    } finally {
      setBusy('');
    }
  };

  return (
    <>
      <div className="settings-section">
        admitted binaries ({items?.length ?? 0})
        <button
          className="btn btn-mini"
          onClick={() => setAdding((a) => !a)}
          title="admit a new binary"
        >
          {adding ? '−' : '+ admit'}
        </button>
      </div>

      {adding && (
        <div className="admit-form">
          <input
            className="input input-sm"
            placeholder="binary name (e.g. claude)"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            spellCheck={false}
            autoCapitalize="off"
            autoCorrect="off"
          />
          <div className="cap-row">
            {ALL_CAPS.map((c) => (
              <button
                key={c}
                className={`cap-chip ${newCaps.includes(c) ? 'on' : ''}`}
                onClick={() => toggleCap(c)}
                type="button"
              >
                {c}
              </button>
            ))}
            <span className="ttl-field">
              ttl
              <input
                className="input input-xs"
                type="number"
                min={1}
                value={newTtlDays}
                onChange={(e) => setNewTtlDays(Number(e.target.value))}
              />
              d
            </span>
            <button className="btn btn-mini btn-primary" onClick={submitNew} disabled={!!busy}>
              admit
            </button>
          </div>
        </div>
      )}

      {err && <div className="error-msg">{err}</div>}
      {items && items.length === 0 && <div className="empty">no admitted binaries</div>}
      {items &&
        items.map((a) => (
          <div className="admission-row" key={a.name}>
            <div className="adm-main">
              <code className={a.revoked || a.expired ? 'dim' : ''}>{a.name}</code>
              <span className="adm-caps">
                {a.caps.length ? (
                  a.caps.map((c) => (
                    <span className="cap-chip on sm" key={c}>
                      {c}
                    </span>
                  ))
                ) : (
                  <span className="dim">no caps</span>
                )}
              </span>
              {a.revoked ? (
                <span className="bad sm">revoked</span>
              ) : a.expired ? (
                <span className="dim sm">expired</span>
              ) : (
                <span className="ok sm">active</span>
              )}
            </div>
            <div className="adm-actions">
              {!a.revoked && (
                <button
                  className="btn btn-mini"
                  onClick={() => revoke(a.name)}
                  disabled={busy === a.name}
                  title="lock down — revoke this grant"
                >
                  lock
                </button>
              )}
              <button
                className="btn btn-mini btn-danger"
                onClick={() => remove(a.name)}
                disabled={busy === a.name}
                title="remove admission entirely"
              >
                remove
              </button>
            </div>
          </div>
        ))}
    </>
  );
}

/// Live terminal for an interactive PTY session. Streams `pty:output` into a
/// scrollback buffer, forwards keystrokes to the program via `pty_write`, and
/// strips ANSI for a clean (if non-cursor-addressable) view. Good enough for
/// line-oriented interactive tools (claude, python, ssh prompts); full-screen
/// curses apps (vim) will look rough until we add an xterm.js renderer.
// Vendored xterm.js exposes window.Terminal + window.FitAddon (UMD).
type XTerm = {
  open(el: HTMLElement): void;
  write(data: string): void;
  onData(cb: (data: string) => void): void;
  dispose(): void;
  focus(): void;
  loadAddon(addon: unknown): void;
  refresh(start: number, end: number): void;
  clearTextureAtlas?: () => void;
  cols: number;
  rows: number;
};
type XFitAddon = { fit(): void };
declare global {
  interface Window {
    Terminal?: new (opts?: Record<string, unknown>) => XTerm;
    FitAddon?: { FitAddon: new () => XFitAddon };
  }
}

// xterm mounts its DOM into this div imperatively. React must NEVER reconcile
// it, or a parent re-render (cwd polling, etc.) wipes xterm's appended nodes
// (observed: host stays connected but childCount drops to 0, terminal goes
// blank while the Terminal JS object lives on). memo with an always-equal
// comparator freezes the node so React leaves xterm's children alone.
const XtermHost = React.memo(
  React.forwardRef<HTMLDivElement>(function XtermHost(_props, ref) {
    return <div className="xterm-host" ref={ref} />;
  }),
  () => true
);

function PtyTerminal({
  ptyId,
  command,
  onClose,
  onExit,
}: {
  ptyId: string;
  command: string;
  onClose: () => void;
  onExit?: () => void;
}) {
  const [buffer, setBuffer] = useState('');
  const [exited, setExited] = useState(false);
  // Full VT emulation via vendored xterm.js v5.5.0 (+ FitAddon). DEFAULT ON —
  // full-screen TUIs (vim, top, claude) render in a real terminal grid. The
  // long-standing blank render was NOT a renderer bug: the host div is
  // React-owned, so a parent re-render reconciled away xterm's imperatively
  // appended DOM (host stayed connected, childCount → 0). Fixed by mounting
  // into <XtermHost>, a memoized never-re-rendering node. Set moonshine.xterm=0
  // to fall back to the ANSI-stripped scrollback pane.
  const useXterm =
    typeof window !== 'undefined' &&
    !!window.Terminal &&
    !!window.FitAddon &&
    localStorage.getItem('moonshine.xterm') !== '0';
  const hostRef = useRef<HTMLDivElement>(null);
  const screenRef = useRef<HTMLPreElement>(null);
  const termRef = useRef<XTerm | null>(null);

  useEffect(() => {
    let stop = false;
    let unOut: (() => void) | null = null;
    let unExit: (() => void) | null = null;
    let term: XTerm | null = null;
    let fit: XFitAddon | null = null;
    let onResize: (() => void) | null = null;
    let resizeObserver: ResizeObserver | null = null;
    let fitFrame = 0;
    let lastSize: { cols: number; rows: number } | null = null;

    if (useXterm && hostRef.current && window.Terminal && window.FitAddon) {
      term = new window.Terminal({
        cursorBlink: true,
        fontSize: 12,
        fontFamily: "'SF Mono', Menlo, Monaco, monospace",
        theme: { background: '#000000', foreground: '#e0e0e0', cursor: '#00ff9f' },
        scrollback: 5000,
      });
      fit = new window.FitAddon.FitAddon();
      term.loadAddon(fit);
      term.open(hostRef.current);
      term.onData((data) => {
        invoke('pty_write', { sessionId: ptyId, data }).catch(() => {});
      });
      // Fit after the container has laid out (next frame), then size the PTY to
      // match — this is what makes output actually render (a 0-size grid shows
      // nothing). Re-fit + re-resize on window resize.
      const doFitNow = () => {
        if (!fit || !term) return;
        try {
          fit.fit();
          if (term.cols <= 0 || term.rows <= 0) return;
          if (lastSize?.cols === term.cols && lastSize.rows === term.rows) return;
          lastSize = { cols: term.cols, rows: term.rows };
          invoke('pty_resize', { sessionId: ptyId, cols: term.cols, rows: term.rows }).catch(() => {});
        } catch {
          /* container not measurable yet */
        }
      };
      const doFit = () => {
        if (fitFrame) cancelAnimationFrame(fitFrame);
        fitFrame = requestAnimationFrame(() => {
          fitFrame = 0;
          doFitNow();
        });
      };
      requestAnimationFrame(() => {
        doFit();
        term?.focus();
      });
      // CANDIDATE FIX: the DOM renderer measures glyph size once at open(); if
      // that happened before the webfont/layout settled it gets 0 and paints
      // nothing. Re-fit + force a full refresh after fonts are ready and again
      // after a short delay so the char-measure re-runs against the real font.
      const remeasure = () => {
        doFit();
        try {
          term?.refresh(0, (term.rows || 24) - 1);
        } catch {
          /* ignore */
        }
      };
      const fontsReady = (document as unknown as { fonts?: { ready?: Promise<unknown> } }).fonts
        ?.ready;
      if (fontsReady) fontsReady.then(() => requestAnimationFrame(remeasure)).catch(() => {});
      setTimeout(remeasure, 150);
      onResize = doFit;
      window.addEventListener('resize', onResize);
      if ('ResizeObserver' in window) {
        resizeObserver = new ResizeObserver(doFit);
        resizeObserver.observe(hostRef.current);
      }
      termRef.current = term;
    }

    (async () => {
      // For xterm: seed any bytes that landed before this listener attaches
      // (the spawn→first-output race), THEN go live. Seeding before attach —
      // not from the poll loop — means the live deltas never overlap the seed,
      // so output isn't double-printed. Live deltas (not the full buffer) also
      // avoid the 256KB ring-buffer offset problem for long TUI redraws.
      if (term) {
        try {
          const [buf] = await invoke<[string, boolean]>('pty_buffer', { sessionId: ptyId });
          if (buf) term.write(buf);
        } catch {
          /* ignore */
        }
      }
      unOut = await listen<{ session_id: string; data: string }>('pty:output', (e) => {
        if (e.payload.session_id !== ptyId || stop) return;
        if (term) term.write(e.payload.data);
        else setBuffer((b) => (b + e.payload.data).slice(-200_000));
      });
      unExit = await listen<{ session_id: string }>('pty:exit', (e) => {
        if (e.payload.session_id === ptyId) setExited(true);
      });
    })();

    // The scrollback fallback (no xterm) is driven entirely by this poll of the
    // authoritative backend buffer — it recovers fast commands whose output
    // fired before the listener mounted. With xterm active, the listener +
    // pty:exit cover output/exit, so we only poll (slowly) to detect completion.
    let polls = 0;
    const poll = async () => {
      if (stop) return;
      try {
        const [buf, done] = await invoke<[string, boolean]>('pty_buffer', {
          sessionId: ptyId,
        });
        if (!term) {
          setBuffer((b) => (buf.length > b.length ? buf.slice(-200_000) : b));
        }
        if (done) {
          setExited(true);
          if (++polls > 3) return;
        }
      } catch {
        return;
      }
      if (!stop) setTimeout(poll, term ? 500 : 200);
    };
    poll();

    return () => {
      stop = true;
      unOut?.();
      unExit?.();
      if (onResize) window.removeEventListener('resize', onResize);
      resizeObserver?.disconnect();
      if (fitFrame) cancelAnimationFrame(fitFrame);
      term?.dispose();
      termRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [ptyId]);

  // Fallback scrollback: auto-scroll + keystroke forwarding (xterm handles its
  // own when active).
  useEffect(() => {
    if (!useXterm && screenRef.current) {
      screenRef.current.scrollTop = screenRef.current.scrollHeight;
    }
  }, [buffer, useXterm]);

  // When the program exits, blur the (now-dead) terminal and hand focus back to
  // the prompt so the next command isn't swallowed by xterm's textarea.
  useEffect(() => {
    if (exited) onExit?.();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [exited]);

  const onKey = (e: React.KeyboardEvent) => {
    if (useXterm || exited) return;
    let data: string | null = null;
    if (e.key === 'Enter') data = '\r';
    else if (e.key === 'Backspace') data = '\x7f';
    else if (e.key === 'Tab') data = '\t';
    else if (e.key === 'Escape') data = '\x1b';
    else if (e.key === 'ArrowUp') data = '\x1b[A';
    else if (e.key === 'ArrowDown') data = '\x1b[B';
    else if (e.key === 'ArrowRight') data = '\x1b[C';
    else if (e.key === 'ArrowLeft') data = '\x1b[D';
    else if (e.ctrlKey && e.key.length === 1) {
      const c = e.key.toLowerCase().charCodeAt(0);
      if (c >= 97 && c <= 122) data = String.fromCharCode(c - 96);
    } else if (e.key.length === 1 && !e.metaKey) {
      data = e.key;
    }
    if (data !== null) {
      e.preventDefault();
      invoke('pty_write', { sessionId: ptyId, data }).catch(() => {});
    }
  };

  const close = () => {
    invoke('pty_kill', { sessionId: ptyId }).catch(() => {});
    onClose();
  };

  return (
    <div className="pty-pane" tabIndex={useXterm ? undefined : 0} onKeyDown={onKey}>
      <div className="pty-head">
        <span className="pty-title">⌨ {command}</span>
        <span className={`pty-state ${exited ? 'dim' : 'ok'}`}>
          {exited ? 'exited' : 'interactive · live'}
        </span>
        <button className="btn btn-mini" onClick={close} title="close session">
          {exited ? 'close' : 'kill'}
        </button>
      </div>
      {useXterm ? (
        <XtermHost ref={hostRef} />
      ) : (
        <pre className="pty-screen" ref={screenRef}>
          {buffer ? renderAnsi(buffer) : '(starting…)'}
        </pre>
      )}
    </div>
  );
}

export default App;
